# Whitelist of allowed module names to prevent code injection
ALLOWED_MODULES = {
    '': 'urllib',
    '2': 'urllib2',
    '3': 'urllib3',
}

# Static mapping of already-imported, whitelisted modules
_IMPORTED_MODULES = {}


@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version safely.
    '''
    version = request.args.get('version', '')

    # Validate against a strict whitelist to avoid arbitrary code execution
    if version not in ALLOWED_MODULES:
        return 'Invalid module version', 400

    # Resolve to a fixed, known-safe module name from the whitelist
    module_name = ALLOWED_MODULES[version]

    # Import only from a static, whitelisted set of module names
    if module_name not in _IMPORTED_MODULES:
        try:
            # module_name is guaranteed to be a constant from ALLOWED_MODULES
            _IMPORTED_MODULES[module_name] = importlib.import_module(module_name)
        except ImportError:
            return 'Module not found', 404

    module = _IMPORTED_MODULES[module_name]

    # Render with the template engine and escape output to prevent XSS
    return render_template_string(
        'Imported module: {{ name }}',
        name=escape(module.__name__),
    )


