import _pickle as cPickle
import base64
import io


class _RestrictedUnpickler(cPickle.Unpickler):
    """
    A restricted unpickler that refuses to load arbitrary classes/functions.
    This prevents arbitrary code execution (CWE-502) when deserializing
    untrusted data such as HTTP headers.
    """

    # Only allow a minimal set of safe built-in types.
    _SAFE_BUILTINS = {
        'dict',
        'list',
        'tuple',
        'set',
        'frozenset',
        'str',
        'bytes',
        'int',
        'float',
        'bool',
        'complex',
        'NoneType',
    }

    def find_class(self, module, name):
        # Reject anything that is not an explicitly allowed safe builtin.
        if module == 'builtins' and name in self._SAFE_BUILTINS:
            return super().find_class(module, name)
        raise cPickle.UnpicklingError(
            "Forbidden class during unpickling: %s.%s" % (module, name)
        )


def _safe_loads(data):
    return _RestrictedUnpickler(io.BytesIO(data)).load()


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    try:
        # Extract the auth token from the headers.
        if headers is None:
            return None

        token_b64 = None
        # Support dict-like headers and objects exposing .get().
        try:
            token_b64 = headers.get('AuthToken')
        except AttributeError:
            return None

        if not token_b64:
            return None

        # Ensure we have bytes for base64 decoding.
        if isinstance(token_b64, str):
            token_b64 = token_b64.encode('utf-8')

        # Decode base64 with validation to reject malformed input.
        try:
            raw = base64.b64decode(token_b64, validate=True)
        except (base64.binascii.Error, ValueError):
            return None

        # Safely deserialize using the restricted unpickler.
        try:
            token = _safe_loads(raw)
        except (cPickle.UnpicklingError, EOFError, AttributeError,
                ImportError, IndexError, ValueError, TypeError):
            return None

        # Validate the token structure.
        if not isinstance(token, dict):
            return None

        # A valid token must contain the expected fields.
        if not token.get('valid'):
            return None

        return token.get('data')
    except Exception:
        # Never leak internal errors to the caller.
        return None

