import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    try:
        # Extract the auth token from the headers.
        if headers is None:
            return None

        token_b64 = None
        # Support dict-like headers and objects exposing .get().
        try:
            token_b64 = headers.get('AuthToken')
        except AttributeError:
            return None

        if not token_b64:
            return None

        # Ensure we have bytes for base64 decoding.
        if isinstance(token_b64, str):
            token_b64 = token_b64.encode('utf-8')

        # Decode base64 with validation to reject malformed input.
        try:
            raw = base64.b64decode(token_b64, validate=True)
        except (base64.binascii.Error, ValueError):
            return None

        # Safely deserialize using JSON (no code execution risk).
        try:
            token = json.loads(raw.decode('utf-8'))
        except (json.JSONDecodeError, UnicodeDecodeError, ValueError, TypeError):
            return None

        # Validate the token structure.
        if not isinstance(token, dict):
            return None

        # A valid token must contain the expected fields.
        if not token.get('valid'):
            return None

        return token.get('data')
    except Exception:
        # Never leak internal errors to the caller.
        return None
